10	module testbench;
11		reg clk = 1;
12		reg resetn = 0;
13		wire trap;
14	
15		always #5 clk = ~clk;
16	
17		initial begin
18			if ($test$plusargs("vcd")) begin
19				$dumpfile("testbench.vcd");
20				$dumpvars(0, testbench);
21			end
22			repeat (100) @(posedge clk);
23			resetn <= 1;
24			repeat (1000) @(posedge clk);
25			$finish;
26		end
27	
28		wire mem_valid;
29		wire mem_instr;
30		reg mem_ready;
31		wire [31:0] mem_addr;
32		wire [31:0] mem_wdata;
33		wire [3:0] mem_wstrb;
34		reg  [31:0] mem_rdata;
35	
36		always @(posedge clk) begin
37			if (mem_valid && mem_ready) begin
38				if (mem_instr)
39					$display("ifetch 0x%08x: 0x%08x", mem_addr, mem_rdata);
40				else if (mem_wstrb)
41					$display("write  0x%08x: 0x%08x (wstrb=%b)", mem_addr, mem_wdata, mem_wstrb);
42				else
43					$display("read   0x%08x: 0x%08x", mem_addr, mem_rdata);
44			end
45		end
46	
47		picorv32 #(
48		) uut (
49			.clk         (clk        ),
50			.resetn      (resetn     ),
51			.trap        (trap       ),
52			.mem_valid   (mem_valid  ),
53			.mem_instr   (mem_instr  ),
54			.mem_ready   (mem_ready  ),
55			.mem_addr    (mem_addr   ),
56			.mem_wdata   (mem_wdata  ),
57			.mem_wstrb   (mem_wstrb  ),
58			.mem_rdata   (mem_rdata  )
59		);
60	
